  ret = texture( sampler_pw_main, vUv ).xyz*1.26;

  float n;
  vec2 d = uTexSize.zw*audioLow*3;
  n  = clamp01(texture(sampler_pw_main, vUv+d*vec2( 1, 1)).x);
  n += clamp01(texture(sampler_pw_main, vUv+d*vec2( 3, 0)).x);
  n += clamp01(texture(sampler_pw_main, vUv+d*vec2( 1,-1)).x);
  n += clamp01(texture(sampler_pw_main, vUv+d*vec2( 0, 1)).x);
  n += clamp01(texture(sampler_pw_main, vUv+d*vec2( 0,-1)).x);
  n += clamp01(texture(sampler_pw_main, vUv+d*vec2(-1, 1)).x);
  n += clamp01(texture(sampler_pw_main, vUv+d*vec2(-1, 0)).x);
  n += clamp01(texture(sampler_pw_main, vUv+d*vec2(-1,-1)).x);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1.5,2.3,2.9)*0.05 +
                      uTime*vec3(2,2.1,1.6)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y += (noise9).x*.5;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z += (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x += (noise9).z*.5;
float t = 3;
  if (n < 1)
    ret -= t;
